class Solution {
    public int[] separateDigits(int[] nums) {
        int totalLength = 0;
        for (int num : nums) {
            int length = (int) Math.log10(num) + 1;
            totalLength += length;
        }
        int[] result = new int[totalLength];
        int index = 0;
        for (int num : nums) {
            while (num > 0) {
                result[index++] = num % 10;
                num /= 10;
            }
        }
        // Reverse the array to maintain original order
        int left = 0;
        int right = result.length - 1;
        while (left < right) {
            int temp = result[left];
            result[left] = result[right];
            result[right] = temp;
            left++;
            right--;
        }
        return result;
    }
}
